#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N; scanf("%lld", &N);
        long long A = N / 2 + 1;
        printf("%lld\n", A);
    }
    return 0;
}

